mapper.insert:
insert into `user` (
    user_no, phone, email, password_hash, nickname, avatar_url, user_type,
    real_name, id_verify_status, developer_status, skill_tags, intro, rating,
    completed_order_count, status, last_login_at, version, created_at, updated_at
) values (
    #{userNo}, #{phone}, #{email}, #{passwordHash}, #{nickname}, #{avatarUrl}, #{userType},
    #{realName}, #{idVerifyStatus}, #{developerStatus}, #{skillTags}, #{intro}, #{rating},
    #{completedOrderCount}, #{status}, #{lastLoginAt}, #{version}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from `user`
where phone = #{account}
   or email = #{account}
   or user_no = #{account}
limit 1

select from `user`
and status = #{status}
and user_type = #{userType}
and ( user_no like concat('%', #{keyword}, '%') or nickname like concat('%', #{keyword}, '%') or phone like concat('%', #{keyword}, '%') or email like concat('%', #{keyword}, '%') )
order by id desc
